def configure_api_gateway(kong: KongAdminAPI, config: Dict[str, Any]):
    print("Starting Kong API Gateway configuration...")
    
    for service_config in config.get('services', []):
        service_name = service_config['name']
        
        existing_service = kong.get_service(service_name)
        if existing_service:
            print(f"Service {service_name} already exists, updating...")
            service = kong.update_service(service_name, **{k: v for k, v in service_config.items() if k != 'name'})
        else:
            service = kong.create_service(**service_config)
        
        for route_config in service_config.get('routes', []):
            kong.create_route(service_name, **route_config)
        
        if 'upstream' in service_config:
            upstream_config = service_config['upstream']
            upstream_name = upstream_config['name']
            
            existing_upstream = kong.get_upstream(upstream_name)
            if existing_upstream:
                print(f"Upstream {upstream_name} already exists, updating...")
                upstream = kong.update_upstream(upstream_name, **{k: v for k, v in upstream_config.items() if k not in ['name', 'targets']})
            else:
                upstream = kong.create_upstream(**{k: v for k, v in upstream_config.items() if k != 'targets'})
            
            for target in upstream_config.get('targets', []):
                kong.create_target(upstream_name, **target)
        
        for plugin_config in service_config.get('plugins', []):
            kong.add_plugin(service_id=service['id'], **plugin_config)
    
    print("Kong API Gateway configuration completed!")


